#include<bits/stdc++.h>using namespace std;int n,a[1000010],q,b[1000010];int check(int mid){    int sum=0;    for(int i=1;i<=n;i++){    	if(a[i]<=mid){    		sum++;		}		else{			break;		}	}    for(int i=1;i<=q;i++){        if(b[i]>0&&b[i]<mid){            sum++;        }        if(b[i]<0&&abs(b[i])<=sum){            sum--;         }    }    return sum;}int main(){    scanf("%d%d",&n,&q);    for(int i=1;i<=n;i++)scanf("%d",&a[i]);    for(int i=1;i<=q;i++)scanf("%d",&b[i]);    int sum=0;    for(int i=1;i<=q;i++){        if(0>b[i]){            sum++;        }    }    if(q-sum+n<=sum){        cout<<0;        return 0;     }    int l=0,r=n,mid,z=0;    while(l<=r){        mid=(l+r)/2;        if(check(mid)>0){            r=mid-1;            z=mid;        }        else{            l=mid+1;        }     }    cout<<z;    return 0;}